public int nthSuperUglyNumber(int n, int[] primes) {
    int[] dp = new int[n];
    int[] ptr = new int[primes.length];
    dp[0] = 1;

    for (int i = 1; i < n; i++) {
        int next = Integer.MAX_VALUE;
        for (int j = 0; j < primes.length; j++) {
            next = Math.min(next, dp[ptr[j]] * primes[j]);
        }
        dp[i] = next;
        for (int j = 0; j < primes.length; j++) {
            if (dp[ptr[j]] * primes[j] == next) ptr[j]++;
        }
    }

    return dp[n - 1];
}

