from typing import List

def nth_super_ugly_number(n: int, primes: List[int]) -> int:
    dp = [1] * n
    ptr = [0] * len(primes)

    for i in range(1, n):
        candidates = [dp[ptr[j]] * primes[j] for j in range(len(primes))]
        dp[i] = min(candidates)
        for j in range(len(primes)):
            if candidates[j] == dp[i]:
                ptr[j] += 1

    return dp[n - 1]
